    CssTokenIterator atIter = mock(CssTokenIterator.class);
    when(atIter.hasNext(any())).thenReturn(true, false);
    CssToken at = new CssToken(CssToken.Type.ATKEYWORD, "@x", new Location(1,1));
    when(atIter.next(any())).thenReturn(at);

    // Stub scan
    Method scan = CssParser.class.getDeclaredMethod("scan", Reader.class, String.class, CssErrorHandler.class);
    scan.setAccessible(true);
    doReturn(atIter).when(parser).scan(any(Reader.class), anyString(), any(CssErrorHandler.class)); // Changed to match Mockito's when method

    // Stub handleAtRule to throw CssException
    CssException cssEx = new ConcreteCssException(CssErrorCode.GRAMMAR_UNEXPECTED_TOKEN, at.location, Locale.ENGLISH, "err"); // Changed to use a concrete subclass
    Method handleAtRule = CssParser.class.getDeclaredMethod("handleAtRule", 
